#!/usr/bin/env bash
# -*- coding: utf-8 -*-
#
# deploy_xcfui.sh —— x-cfui 中继管理面板 一键部署脚本
#
# 用途:
#   在全新 Debian 12 服务器上，一条命令装好并启动 x-cfui 中继管理面板。
#   部署完成后「无需任何二次操作或命令」即可直接在浏览器访问使用。
#
# 特点:
#   - 所有安全信息全部随机生成: 安全入口密令(entry_token) / 管理员账户 / 管理员密码
#   - 自动安装: xray(固定版本) + nginx + ufw + fail2ban + sshpass + openssl + python3
#   - 自动开启 BBR 拥塞控制
#   - 自动配置防火墙(ufw)放行关键端口, 不会锁死 SSH
#   - 随机凭据同时打印到屏幕 并 保存到 /root/xcfui_credentials.txt
#
# 用法:
#   1) 把本脚本 与 app.py 放在同一目录, 上传到新服务器
#   2) sudo bash deploy_xcfui.sh
#
# 可选环境变量(一般不填, 留空即随机):
#   XCFUI_ENTRY   自定义安全入口密令 (留空=随机12位)
#   XCFUI_USER    自定义管理员账户   (留空=随机)
#   XCFUI_PASS    自定义管理员密码   (留空=随机18位)
#   注: 面板监听端口固定为 5000(app.py 内置 PORT=5000), 不可通过环境变量改。
#
set -euo pipefail

# ===================== 可配置参数 =====================
XRAY_VERSION="${XRAY_VERSION:-v26.3.27}"
PANEL_DIR="/opt/x-cfui"
XRAY_BIN="/usr/local/bin/xray"
XRAY_CONF="/usr/local/etc/xray/config.json"
PORT=5000
SERVICE_PANEL="x-cfui"
SERVICE_XRAY="xray"

log(){ echo -e "\033[1;36m[部署]\033[0m $*"; }
ok(){ echo -e "\033[1;32m[OK]\033[0m $*"; }
warn(){ echo -e "\033[1;33m[警告]\033[0m $*"; }
err(){ echo -e "\033[1;31m[错误]\033[0m $*" >&2; }

# ===================== 前置检查 =====================
if [[ $EUID -ne 0 ]]; then
  err "请使用 root 运行: sudo bash $0"
  exit 1
fi

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
if [[ ! -f "$SCRIPT_DIR/app.py" ]]; then
  err "未找到 app.py, 请将本脚本与 app.py 放在同一目录后运行。"
  exit 1
fi

# 探测系统(非 Debian 12 仅警告, 不阻断)
if command -v lsb_release >/dev/null 2>&1; then
  OS_ID="$(lsb_release -si 2>/dev/null || echo unknown)"
  OS_VER="$(lsb_release -sr 2>/dev/null || echo unknown)"
  if [[ "$OS_ID" != "Debian" ]]; then
    warn "当前系统: $OS_ID $OS_VER (推荐 Debian 12)。将继续尝试, 如遇问题请改用 Debian 12。"
  fi
fi

# ===================== 随机安全信息 =====================
rand_token(){ tr -dc 'a-zA-Z0-9' < /dev/urandom | head -c 12; }
rand_user(){ echo "cfui-$(tr -dc 'a-z0-9' < /dev/urandom | head -c 6)"; }
rand_pass(){ tr -dc 'a-zA-Z0-9!@#%^&*' < /dev/urandom | head -c 18; }

ENTRY_TOKEN="${XCFUI_ENTRY:-$(rand_token)}"
ADMIN_USER="${XCFUI_USER:-$(rand_user)}"
ADMIN_PASS="${XCFUI_PASS:-$(rand_pass)}"
CLIENT_UUID="$(cat /proc/sys/kernel/random/uuid)"
PANEL_KEY="/root/.ssh/xcfui_ed25519"

log "生成的安全信息(部署后可在面板[安全设置]中修改):"
echo "    安全入口密令 : $ENTRY_TOKEN"
echo "    管理员账户   : $ADMIN_USER"
echo "    管理员密码   : $ADMIN_PASS"

# ===================== 安装系统依赖 =====================
log "更新 apt 并安装基础依赖..."
export DEBIAN_FRONTEND=noninteractive
apt-get update -qq
apt-get install -y -qq \
  curl wget unzip openssl ca-certificates gnupg lsb-release \
  python3 python3-pip \
  nginx \
  ufw \
  fail2ban \
  sshpass openssh-client openssh-server \
  qrencode jq iptables >/dev/null 2>&1 || true
ok "基础依赖安装完成"

# 安装面板运行时依赖(segno) — 从内嵌 base64 离线安装(无需网络)
log "安装面板 Python 依赖(segno)..."
if python3 -c "import segno" 2>/dev/null; then
  ok "segno 已安装"
else
  cd /tmp
  mkdir -p /tmp/_segno_install
  cd /tmp/_segno_install
  # 解码内嵌的 segno 包
  cat <<'SEGEOF' | base64 -d | tar -xz

SEGEOF
  PYTHON_SITE="$(python3 -c "import site; print(site.getsitepackages()[0])" 2>/dev/null)"
  if [[ -n "$PYTHON_SITE" && -d /tmp/_segno_install/segno ]]; then
    cp -r /tmp/_segno_install/segno "$PYTHON_SITE/segno"
    rm -rf /tmp/_segno_install
    ok "segno 已从内嵌包离线安装"
  else
    warn "segno 离线安装失败, 二维码生成不可用"
  fi
  cd /
fi

# ===================== 安装 Xray(固定版本) =====================
install_xray(){
  mkdir -p /usr/local/etc/xray /usr/local/bin
  if [[ -x "$XRAY_BIN" ]]; then
    ok "xray 已存在: $($XRAY_BIN version | head -1)"
    return 0
  fi
  # 优先从内嵌 base64 离线安装
  if [[ -n "$XRAY_B64" ]]; then
    log "从内嵌包离线安装 Xray ..."
    echo "$XRAY_B64" | base64 -d | gunzip -c > "$XRAY_BIN" 2>/dev/null
    chmod +x "$XRAY_BIN"
    if [[ -x "$XRAY_BIN" ]]; then
      ok "Xray 已从内嵌包离线安装: $($XRAY_BIN version | head -1)"
      return 0
    fi
  fi
  # 兜底: 从网络下载(GitHub 用户无内嵌包时使用)
  # 多镜像轮询, 覆盖国内可用加速源
  log "下载 Xray $XRAY_VERSION (多镜像轮询)..."
  local urls=(
    "https://ghfast.top/https://github.com/XTLS/Xray-core/releases/download/${XRAY_VERSION}/Xray-linux-64.zip"
    "https://ghproxy.com/https://github.com/XTLS/Xray-core/releases/download/${XRAY_VERSION}/Xray-linux-64.zip"
    "https://hub.gitmirror.com/https://github.com/XTLS/Xray-core/releases/download/${XRAY_VERSION}/Xray-linux-64.zip"
    "https://cdn.jsdelivr.net/gh/XTLS/Xray-core@${XRAY_VERSION}/Xray-linux-64.zip"
    "https://github.com/XTLS/Xray-core/releases/download/${XRAY_VERSION}/Xray-linux-64.zip"
  )
  local zip="/tmp/Xray-linux-64.zip"
  local downloaded=false
  for url in "${urls[@]}"; do
    if curl -fsSL --connect-timeout 10 -o "$zip" "$url" 2>/dev/null; then
      downloaded=true
      break
    fi
  done
  if $downloaded; then
    unzip -o "$zip" -d /tmp/xe >/dev/null
    cp /tmp/xe/xray "$XRAY_BIN"
    chmod +x "$XRAY_BIN"
    rm -rf /tmp/xe "$zip"
    ok "Xray 安装完成: $($XRAY_BIN version | head -1)"
  else
    warn "Xray 下载失败, 请手动安装到 /usr/local/bin/xray"
    return 1
  fi
}
# 在 install_xray 前定义 XRAY_B64(空串则走网络)
XRAY_B64=""
install_xray

# ===================== 写入 systemd 单元 =====================
log "写入 systemd 服务单元..."
cat > /etc/systemd/system/${SERVICE_XRAY}.service <<'XEOF'
[Unit]
Description=Xray Proxy Service (relay node)
After=network.target

[Service]
User=root
ExecStart=/usr/local/bin/xray run -config /usr/local/etc/xray/config.json
Restart=on-failure
RestartSec=3

[Install]
WantedBy=multi-user.target
XEOF

cat > /etc/systemd/system/${SERVICE_PANEL}.service <<'PSEOF'
[Unit]
Description=x-cfui Xray Admin Panel (relay controller)
After=network.target

[Service]
User=root
WorkingDirectory=/opt/x-cfui
ExecStart=/usr/bin/python3 /opt/x-cfui/app.py
Restart=on-failure
RestartSec=3

[Install]
WantedBy=multi-user.target
PSEOF
ok "systemd 单元已写入"

# ===================== 部署面板文件 + 初始 state =====================
log "部署面板文件..."
mkdir -p "$PANEL_DIR"
cp "$SCRIPT_DIR/app.py" "$PANEL_DIR/app.py"
chmod 644 "$PANEL_DIR/app.py"
chown root:root "$PANEL_DIR/app.py"

# 初始 state.json: 全新空节点(用户后续在面板中添加自己的出口/入口)
# 全新部署时本机就是入口节点, 故 cn_addr 取本机公网 IP(无外网则退而用 hostname -I 第一字段)
_DEPLOY_PUB_IP="$(curl -fsSL -m 5 ifconfig.me 2>/dev/null || echo '')"
_DEPLOY_CN_IP="${_DEPLOY_PUB_IP:-$(hostname -I 2>/dev/null | awk '{print $1}')}"
cat > "$PANEL_DIR/state.json" <<EOF
{
  "admin_user": "${ADMIN_USER}",
  "admin_pass": "${ADMIN_PASS}",
  "entry_token": "${ENTRY_TOKEN}",
  "client_uuid": "${CLIENT_UUID}",
  "client_fp": "chrome",
  "cn_ssh_port": 22,
  "cn_addr": "${_DEPLOY_CN_IP}",
  "exits": [],
  "inbounds": [],
  "routing_rules": [],
  "smart_routing": false,
  "public_hosts": [],
  "site_title": "x-cfui",
  "site_footer": "QQ: 123008"
}
EOF
chmod 600 "$PANEL_DIR/state.json"
ok "state.json 已生成(安全信息已随机)"

# ===================== 初始最小 xray 配置(保证 xray 服务可启动) =====================
# 用户通过面板添加入口/出口后, 面板会自动重写此文件。
cat > "$XRAY_CONF" <<'CEOF'
{
  "log": {
    "loglevel": "warning",
    "access": "/var/log/xray-access.log",
    "error": "/var/log/xray-error.log"
  },
  "inbounds": [
    {
      "listen": "127.0.0.1",
      "port": 10999,
      "protocol": "dokodemo-door",
      "settings": { "address": "127.0.0.1", "port": 10999, "network": "tcp" },
      "tag": "local-health"
    }
  ],
  "outbounds": [
    { "protocol": "freedom", "tag": "direct" }
  ],
  "routing": { "rules": [] }
}
CEOF
mkdir -p /var/log
ok "初始 xray 配置已写入"

# ===================== 面板管理密钥(用于面板 SSH 管理 cn/自身) =====================
if [[ ! -f "$PANEL_KEY" ]]; then
  mkdir -p /root/.ssh
  chmod 700 /root/.ssh
  ssh-keygen -t ed25519 -f "$PANEL_KEY" -N "" -C "xcfui-panel" >/dev/null 2>&1
fi
if [[ -f "${PANEL_KEY}.pub" ]]; then
  mkdir -p /root/.ssh
  chmod 700 /root/.ssh
  cat "${PANEL_KEY}.pub" >> /root/.ssh/authorized_keys
  chmod 600 /root/.ssh/authorized_keys
fi
ok "面板管理密钥就绪"

# ===================== BBR 拥塞控制 =====================
log "开启 BBR..."
cat > /etc/sysctl.d/99-bbr.conf <<'BEOF'
net.core.default_qdisc=fq
net.ipv4.tcp_congestion_control=bbr
net.ipv4.tcp_syn_retries=2
net.ipv4.tcp_retries1=3
net.ipv4.tcp_retries2=5
net.ipv4.tcp_mtu_probing=1
net.ipv4.tcp_keepalive_time=30
net.ipv4.tcp_keepalive_intvl=5
net.ipv4.tcp_keepalive_probes=3
net.core.rmem_max=67108864
net.core.wmem_max=67108864
net.ipv4.tcp_rmem=4096 87380 67108864
net.ipv4.tcp_wmem=4096 65536 67108864
BEOF
sysctl --system >/dev/null 2>&1 || true
modprobe tcp_bbr 2>/dev/null || true
ok "BBR 已配置 (当前: $(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null))"

# ===================== 网站目录(供面板[网站设置]使用) =====================
if [[ ! -d /var/www/html ]]; then
  mkdir -p /var/www/html
fi
if [[ ! -f /var/www/html/index.html ]]; then
  cat > /var/www/html/index.html <<'HEOF'
<!doctype html><html><head><meta charset="utf-8"><title>x-cfui</title></head>
<body><h1>x-cfui</h1><p>中继管理面板 — 网站根目录 /var/www/html</p></body></html>
HEOF
fi
ok "网站目录就绪"

# ===================== 防火墙(ufw) =====================
log "配置防火墙(ufw)..."
# 先放行当前 SSH 连接端口, 避免启用 ufw 后锁死
if [[ -n "${SSH_CONNECTION:-}" ]]; then
  sshp="$(echo "$SSH_CONNECTION" | awk '{print $4}')"
  ufw allow "${sshp}/tcp" >/dev/null 2>&1 || true
fi
ufw allow 22/tcp >/dev/null 2>&1 || true
ufw allow ${PORT}/tcp >/dev/null 2>&1 || true
ufw allow 443/tcp >/dev/null 2>&1 || true
ufw allow 8443/tcp >/dev/null 2>&1 || true
ufw allow 10443/tcp >/dev/null 2>&1 || true
# 先确保没有默认的 deny 把已建立的连接断掉
ufw --force enable >/dev/null 2>&1 || true
ok "防火墙已启用(已放行 SSH/面板/443/8443/10443)"

# ===================== fail2ban 防护(jail) =====================
# Debian 12 的 fail2ban 默认不启用任何 jail, 这里显式开启 sshd 防暴力破解, 否则装了等于没防
log "配置 fail2ban sshd 防护..."
mkdir -p /etc/fail2ban/jail.d
cat > /etc/fail2ban/jail.d/sshd.local <<'FEOF'
[sshd]
enabled = true
port = ssh
filter = sshd
logpath = /var/log/auth.log
maxretry = 5
bantime = 1h
findtime = 10m
FEOF
ok "fail2ban jail 已配置"

# ===================== 启动服务 =====================
log "重载并启动服务..."
systemctl daemon-reload
systemctl enable "$SERVICE_XRAY" "$SERVICE_PANEL" fail2ban nginx >/dev/null 2>&1 || true

systemctl restart "$SERVICE_XRAY" || true
sleep 1
systemctl restart fail2ban || true
nginx -t >/dev/null 2>&1 && systemctl restart nginx || true
systemctl restart "$SERVICE_PANEL" || true
sleep 2

# ===================== 自检 =====================
PANEL_ACTIVE="$(systemctl is-active "$SERVICE_PANEL" 2>/dev/null || echo inactive)"
XRAY_ACTIVE="$(systemctl is-active "$SERVICE_XRAY" 2>/dev/null || echo inactive)"

# 探测本机 IP
LOCAL_IP="$(hostname -I 2>/dev/null | awk '{print $1}')"
PUB_IP="$(curl -fsSL -m 5 ifconfig.me 2>/dev/null || echo '')"

# 保存凭据
CRED_FILE="/root/xcfui_credentials.txt"
{
  echo "x-cfui 部署凭据 ($(date))"
  echo "安全入口 : http://${LOCAL_IP}:${PORT}/${ENTRY_TOKEN}"
  [[ -n "$PUB_IP" ]] && echo "公网入口 : http://${PUB_IP}:${PORT}/${ENTRY_TOKEN}"
  echo "管理员账户: $ADMIN_USER"
  echo "管理员密码: $ADMIN_PASS"
  echo "面板监听端口: $PORT"
} > "$CRED_FILE"
chmod 600 "$CRED_FILE"

# ===================== 完成 =====================
echo
echo -e "\033[1;32m================ 部署完成 ================\033[0m"
echo -e " 安全入口(浏览器打开): \033[1;33mhttp://${LOCAL_IP}:${PORT}/${ENTRY_TOKEN}\033[0m"
[[ -n "$PUB_IP" ]] && echo -e " 公网入口(若已放行):   \033[1;33mhttp://${PUB_IP}:${PORT}/${ENTRY_TOKEN}\033[0m"
echo -e " 管理员账户: \033[1;33m${ADMIN_USER}\033[0m"
echo -e " 管理员密码: \033[1;33m${ADMIN_PASS}\033[0m"
echo " 面板服务: $PANEL_ACTIVE | Xray: $XRAY_ACTIVE"
echo -e " 凭据已保存: \033[1;33m$CRED_FILE\033[0m"
echo -e "\033[1;32m==========================================\033[0m"
echo
if [[ "$PANEL_ACTIVE" != "active" || "$XRAY_ACTIVE" != "active" ]]; then
  warn "有服务未处于 active 状态, 请检查: journalctl -u $SERVICE_PANEL / journalctl -u $SERVICE_XRAY"
else
  ok "所有服务已启动, 直接打开上面的安全入口即可使用。"
fi
